DELETE FROM tb_veh_security_constant t
WHERE t.id IN

    #{id}

mapper.select:
SELECT 
FROM tb_veh_security_constant t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.vin = #{vin}


    AND t.batch_num = #{batchNum}


    AND t.preset_state = #{presetState}


    AND t.kms_key_ref = #{kmsKeyRef}


    AND t.fail_reason = #{failReason}


    AND t.gen_time = #{genTime}


    AND t.last_attempt_time = #{lastAttemptTime}


    AND t.constant_type = #{constantType}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.id DESC
